/**
 * Share-specific information related to this document.
 */
export interface ShareInfo {
    /**
     * Indicates whether the document is shared with at least one user. This means it's true if one of the following applies:
     * - The document is public
     * - There is at least one direct share with at least one user or group
     * - There is at least one environment share, regardless of how many users have claimed that share
     */
    isShared?: boolean;
    /**
     * Indicates whether the document is shared with the user that has requested it.
     */
    isSharedWithCurrentUser?: boolean;
}
